        // handle extra whitespace in between element name and attribute on open and close tags
        var spacerunRE = XRegExp('/<\\s*?span\\s*?style="xfa-spacerun:yes"\\s*?>(\\s+)<\/\\s*?span\\s*?>/', 'gis');
