        isSame : function(v) {
            return (this._originalVersion == v);
        },

        isAfter: function(v) {
            return (this._originalVersion > v);
        },

        isAfterOrSame : function(v) {
            return this.isAfter(v) || this.isSame(v);
        },

        isPrevious: function(v) {
            return (this._originalVersion < v);
        },

        isPreviousOrSame : function(v) {
            return this.isPrevious(v) || this.isSame(v);
        },

